// src/HangmanGame.js
import "./App.css";
import React from "react";
import LetterBox from "./LetterBox";
import SingleLetterSearchBar from "./SingleLetterSearchBar"; // note the capital B

// Keep your original image names (put PNGs in /public)
const pics = ["noose.png", "upperBody.png", "upperandlower.png", "1arm.png", "botharms.png", "1leg.png", "Dead.png"];

// Keep your original starter words
const words = ["Morehouse", "Spelman", "Basketball", "Table", "Museum", "Excellent", "Fun", "React"];

class HangmanGame extends React.Component {
  state = {
    wordList: [],
    curWord: 0,          // index into wordList
    lifeLeft: 0,         // wrong guesses so far (we keep your var name)
    usedLetters: [],     // all letters tried (lowercase)
    gameStatus: "idle",  // "idle" | "playing" | "won" | "lost"
    playerName: "",      // (kept from your original)
  };

  componentDidMount() {
    // same pattern you had
    this.setState({ wordList: words });
  }

  // kept from your original
  getPlayerName = (name) => {
    this.setState({ playerName: name });
  };

  // Start/Reset a game
  startNewGame = () => {
    const { wordList } = this.state;
    if (!wordList || wordList.length === 0) return;

    this.setState({
      curWord: Math.floor(Math.random() * wordList.length),
      lifeLeft: 0,
      usedLetters: [],
      gameStatus: "playing",
    });
  };

  // Handle a single-letter guess from the search bar
  onGuess = (raw) => {
    const { gameStatus, usedLetters, lifeLeft } = this.state;
    if (gameStatus !== "playing") return;

    const letter = (raw || "").toLowerCase().trim();
    if (!/^[a-z]$/.test(letter)) return;
    if (usedLetters.includes(letter)) return; // already tried

    const nextUsed = [...usedLetters, letter];
    const word = this.currentWord();
    const normalized = word.toLowerCase();

    if (normalized.includes(letter)) {
      // correct guess — check solved
      const solved = this.isSolved(normalized, nextUsed);
      this.setState({
        usedLetters: nextUsed,
        gameStatus: solved ? "won" : "playing",
      });
    } else {
      // WRONG GUESS (this was where your " } el" typo happened — must be "} else {")
      const nextWrongCount = lifeLeft + 1;
      const maxWrong = Math.max(pics.length - 1, 0);
      const lost = nextWrongCount >= maxWrong;
      this.setState({
        usedLetters: nextUsed,
        lifeLeft: nextWrongCount,
        gameStatus: lost ? "lost" : "playing",
      });
    }
  };

  // ===== helpers =====
  currentWord = () => {
    const { wordList, curWord } = this.state;
    return wordList && wordList.length > 0 ? wordList[curWord] || "" : "";
  };

  isSolved = (normalizedWord, used) => {
    return normalizedWord.split("").every((ch) => !/[a-z]/.test(ch) || used.includes(ch));
  };

  maskedWord = (word, used) => {
    return word
      .split("")
      .map((ch) => {
        if (!/[a-z]/i.test(ch)) return ch; // keep spaces/punct
        return used.includes(ch.toLowerCase()) ? ch : "_";
      })
      .join(" ");
  };

  wrongLetters = (word, used) => {
    const set = new Set(word.toLowerCase().split(""));
    return used.filter((l) => !set.has(l));
  };

  correctLetters = (word, used) => {
    const set = new Set(word.toLowerCase().split(""));
    return used.filter((l) => set.has(l));
  };

  render() {
    const { lifeLeft, usedLetters, gameStatus } = this.state;
    const word = this.currentWord();

    const correct = this.correctLetters(word, usedLetters);
    const wrong = this.wrongLetters(word, usedLetters);

    const maxWrong = Math.max(pics.length - 1, 0);      // number of drawable steps
    const livesRemaining = Math.max(maxWrong - lifeLeft, 0);

    // Use images from /public
    const imgIndex = Math.min(lifeLeft, pics.length - 1);
    const imgSrc = `${process.env.PUBLIC_URL}/${pics[imgIndex]}`;

    const masked = this.maskedWord(word, usedLetters);

    return (
      <div className="page">
        {/* Header + New Game */}
        <header className="header">
          <button className="newGameBtn" onClick={this.startNewGame}>
            New Game
          </button>
        </header>

        <div className="board">
          {/* LEFT: Letters Guessed + Missed */}
          <aside className="left">
            <div className="lettersBox">
              <div className="lettersTitle">Letters Guessed</div>
              <div className="lettersList">
                {correct.length === 0 ? (
                  <span className="muted">—</span>
                ) : (
                  correct.map((c) => <LetterBox key={`c-${c}`} letter={c} isVisible />)
                )}
              </div>

              <div className="lettersTitle sub">Missed</div>
              <div className="lettersList">
                {wrong.length === 0 ? (
                  <span className="muted">—</span>
                ) : (
                  wrong.map((c) => <LetterBox key={`w-${c}`} letter={c} isVisible wrong />)
                )}
              </div>
            </div>
          </aside>

          {/* CENTER: Title + Image + Word + Input */}
          <main className="center">
            <h1 className="title">Hangman</h1>

            {/* Image based on wrong guesses */}
            <img
              src={imgSrc}
              alt="hangman"
              style={{ maxWidth: "380px", margin: "8px auto", display: "block" }}
            />

            {/* Masked word */}
            <div className="wordDisplay">{masked}</div>

            {/* Search bar */}
            <SingleLetterSearchBar
              onGuess={this.onGuess}
              disabled={gameStatus !== "playing"}
            />
          </main>

          {/* RIGHT: Lives */}
          <aside className="right">
            <div className="livesBox">
              <div className="livesLabel">Lives Left</div>
              <div className="livesNum">{livesRemaining}</div>
            </div>
          </aside>
        </div>

        {/* Win/Lose popup */}
        {gameStatus !== "playing" && gameStatus !== "idle" && (
          <div className="overlay" role="dialog" aria-modal="true">
            <div className="modal">
              <h2>{gameStatus === "won" ? "You Win! 🎉" : "You Lost 💀"}</h2>
              {gameStatus === "lost" && (
                <p className="reveal">
                  The word was: <strong>{word.toUpperCase()}</strong>
                </p>
              )}
              <button className="newGameBtn" onClick={this.startNewGame}>
                Play Again
              </button>
            </div>
          </div>
        )}
      </div>
    );
  }
}

export default HangmanGame;
